import React, { Fragment, useEffect, useState } from 'react';
import { Card, CardBody, CardHeader, Col, Container, FormGroup, Label, Row } from 'reactstrap';
import Breadcrumb from '../components/common/Breadcrumb';
import { getFetch } from '../config/fetchData';

const AddSource = () => {
  const [methods, setMethods] = useState([]);
  const [methodId, setMethodId] = useState(null);
  useEffect(() => {
    if (methods.length === 0) {
      getFetch(`/Method/all`).then((data) => { setMethods(data.Data); });
    }
  }, []);
  const formSubmitHandler = (e) => {
    e.preventDefault();
  }
  return (
    <Fragment>
      <Breadcrumb title="Create Source" parent="Sources" />
      <Container fluid={true}>
        <Form onSubmit={formSubmitHandler}>
          <Row className="product-adding">
            <Col xl="12">
              <Card>
                <CardHeader>
                  <h5>Source</h5>
                </CardHeader>
                <CardBody>
                  <div className="digital-add needs-validation">
                    <FormGroup>
                      <Label className="col-form-label">
                        <span>*</span> Method
                      </Label>
                      <select className="custom-select" required="" name='method' onChange={(e) => { setMethodId({ _id: e.target.value, title: e.target.selectedOptions[0].innerHTML }) }}>
                        <option value="null">--Select--</option>
                        {
                          methods.length > 0 &&
                          methods.map((element) => {
                            return <option value={element._id} key={element._id}>{element.description}</option>
                          })
                        }
                      </select>
                    </FormGroup>
                  </div>
                </CardBody>
              </Card>
            </Col>
          </Row>
        </Form>
      </Container>
    </Fragment>
  )
}

export default AddSource
